INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05660', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項，何者最適合表達世事無常的心情？', '["蒼狗浮空驚易失，白駒過隙若為留", "曾經滄海難為水，除却巫山不是雲", "北海雖賒，扶搖可接；東隅已逝，桑榆非晚", "徒行與露坐，安穩無後虞。所以古達人，秋風憶蓴鱸"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05661', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '一日的時光其實是一段完美具足的生命，每一剎那都自有其美麗。然而，強燈奪走了暮色，那沉 潛安靜的時分，那鳥歸巢獸返穴的莊嚴行列，在今天這個時代，全都遭人註銷，化為明燦的森嚴 的厲光。（張曉風〈我的幽光實驗〉） 本段文字主要之意旨，下列何者最為接近？', '["只要平心靜氣，就能欣賞到自然的光景無限美好", "科技文明與時俱進，使人們得以享受更便利的生活", "人為的力量強行介入，使得鳥獸畏懼，不再接近人類", "科技文明的進步，使人們棄守了感官本能，喪失了感知大自然美好的機會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05662', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '商禽〈長頸鹿〉：「那個年輕的獄卒發覺囚犯們每次體格檢查時身長的逐月增加都是在脖子之後， 他報告典獄長說：『長官，窗子太高了！』而他得到的回答卻是：『不！他們瞻望歲月。』／仁 慈的青年獄卒，不識歲月的容顏，不知歲月的籍貫，不明歲月的行蹤；乃夜夜往動物園中，到長 頸鹿欄下，去逡巡，去守候。」下列敘述，何者與此詩的涵義最切合？', '["呼籲社會重視人權，改善囚犯們的生活條件與環境", "批評當權者往往不正視問題所在，遇事敷衍搪塞，十足的官僚作風", "諷刺青年獄卒因缺乏經驗，無法勝任工作，而被調去動物園看守長頸鹿", "隱喻即使窗子降低了，囚犯們的脖子還是會增長，顯現出一種渴望求生的意志"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05663', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '我經常問朋友，注意過電線桿的形狀嗎？電線桿的造型，像什麼呢？電線桿的顏色、材質都各不 相同，上頭白色的「礙子」數目，也各有不同，常將天際線切割出某種視野，像一個一個佇立的 衛兵，有時像調皮的頑童，各有其生命，創造出不同圖像或象徵。（李崇建〈審美〉）下列選項 何者最有可能是作者想表達的意思？', '["柳暗花明又一村", "天生我材必有用", "萬物靜觀皆自得", "秋水共長天一色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05664', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「那純粹是另一種玫瑰／自火焰中誕生／在蕎麥田裏他們遇見最大的會戰／而他的一條腿訣別 於一九四三年／他曾聽到過歷史和笑／甚麼是不朽呢／咳嗽藥刮臉刀上月房租如此等等／而在 妻的縫紉機的零星戰鬥下／他覺得唯一能俘虜他的／便是太陽」，本詩主旨為：', '["思索生命存在的意義", "感慨英雄晚年的貧困", "描述戰爭的殘酷恐怖", "反諷社會的黑暗現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05665', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩句，何者與張九齡〈望月懷遠〉「海上生明月，天涯共此時」之意最不相同？', '["謝莊〈月賦〉「隔千里兮共明月」", "蘇軾〈水調歌頭〉「但願人長久，千里共嬋娟」", "張若虛〈春江花月夜〉「春江潮水連海平，海上明月共潮生」", "王建〈十五夜望月寄杜郎中〉「今夜月明人盡望，不知秋思落誰家」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05666', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「《離騷》為屈大夫之哭泣，《莊子》為蒙叟之哭泣，《史記》為太史公之哭泣，《草堂詩集》 為「」之哭泣；李後主以詞哭；八大山人以「」哭；王實甫寄哭泣於《西廂》；曹雪芹寄哭泣於 《紅樓夢》。」 上列文句，「」依序應填入：', '["白居易／詩", "李白／詞", "王維／書", "杜甫／畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05667', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '很多人認為，物質財富是他們生命的反映，是他們存在的證明。他們有意或無意地把自己的身分 和形象，與擁有物聯繫一起。他們擁有愈多，就愈感到安全和有成就。他們覬覦一切：物質財富、 生意成功、藝術品……甚至自我。 下列甲乙丙丁戊敘述，那些所言與本段文字所述「生命反映」、「存在證明」的心態完全相反？ 甲、貴身賤外物，抗跡遠塵軌。 乙、立身馳富貴，處事友四海。 丙、是非不由己，禍患安可防。 丁、中懷苟有主，外物安能縈。 戊、屏除身外物，擺落世間緣。', '["甲丁戊", "乙丙戊", "乙丁戊", "甲乙丙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05668', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '清代學者段玉裁，書寫成後擺在家裏二十年，天天修改，結果可評之處仍多，有人以為可改正處 占百分之三十，在歷史上考得七十分，已堪稱一代鉅著；又像王念孫父子，極善引用類書佚文， 旁徵博引，後人讚美他精確出眾，可以考得八十分，那真是罕見儔匹的考據家；更如程瑤田，幾 乎言出必中，極少錯謬，後人給他評分可高達九十分以上，但他的著作不多，幾乎不對就不寫， 於是影響力也相對減小，反不足與段王諸家相匹敵。（黃永武〈長城與蟻穴〉）上文要意與下列 何者最為接近？', '["莫將黑白定對錯，細為是非找因由", "寧為君子所責修，毋為君子所包容", "小疵不足以損大器，短疢不足以累長才", "建功立業者必謙圓之士，敗事失機者必執拗之人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05669', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '有一個大海和小水滴的故事。有一天，小水滴問大海說：「大海，我不了解你究竟是什麼？」大 海說：「你靠過來，就會明白的。」小水滴向前走去：「哎喲！我的腳不見了。」大海說：「不 用怕！再向前來。」最後大海擁抱了小水滴，不久，海中冒出了小水滴的聲音：「大海，我懂得 你了！」（宋雅姿《坐看雲起時》）上文寓意與下列何項敘述相近？', '["為山九仞，功虧一簣", "原泉混混，不舍晝夜，盈科而後進", "道非聲色，微妙難見。如人飲水，冷暖自知", "天下事有難易乎！為之則難者易，不為則易者難矣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
